        let c = input[i + 2]
        result.push(_b64EncodeChar(a >> 2))
        result.push(_b64EncodeChar(((a & 3) << 4) | (b >> 4)))
        result.push(_b64EncodeChar(((b & 15) << 2) | (c >> 6)))
        result.push(_b64EncodeChar(c & 63))
        i = i + 3
