        // ICANON (0x100) + IEXTEN (0x400) in byte 1. Clearing ISIG is what makes
        // ctrl-c/ctrl-z pass through as raw bytes to the PTY instead of signalling
        // this process — without it, ctrl-c kills the client itself.
        let b0 = raw[24] as i32
        raw[24] = (b0 & 0x77) as u8
        let b1 = raw[25] as i32
        raw[25] = (b1 & 0xFA) as u8

        // clear IXON (c_iflag bit 0x200 → byte 1, 0x02) so ctrl-s/ctrl-q reach
        // the app as raw bytes instead of pausing/resuming output via XON/XOFF
        // flow control — otherwise ctrl-s silently freezes a TUI.
